#include <stdio.h>
#include <math.h>

long long legendre(long long n, long long p) {
    long long result = 0;
    long long i = p;
    while (i <= n) {
        result += n / i;
        i *= p;
    }
    return result;
}

int main() {
    int C;
    scanf("%d", &C);
    while (C--) {
        long long low, high, plow, phigh, t;
        scanf("%lld %lld %lld %lld %lld", &low, &high, &plow, &phigh, &t);
        int count = 0;
        for (long long i = low; i <= high; i++) {
            int found = 0;
            for (long long j = plow; j <= phigh; j++) {
                long long prime = j;
                // calculate the jth prime number
                long long p = 2;
                int k = 1;
                while (k < j) {
                    p++;
                    while (p % 2 == 0 || p % 3 == 0 || p % 5 == 0 || p % 7 == 0) {
                        p++;
                    }
                    k++;
                }
                if (legendre(i, p) == t) {
                    found = 1;
                    break;
                }
            }
            if (found) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

